import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Hash, Plus } from 'lucide-react';

export const AdminTaxonomy = () => {
  const [tags, setTags] = useState<any[]>([]);
  useEffect(() => { AdminService.getAllTaxonomy().then(res => setTags(res.data)); }, []);

  return (
    <div className="space-y-8">
      <h1 className="text-4xl font-black uppercase italic">Archive <span className="text-primary">Taxonomy</span></h1>
      <div className="flex flex-wrap gap-3">
        {tags.map((tag: any) => (
          <div key={tag._id} className="bg-white px-6 py-3 rounded-full border border-gray-100 font-black uppercase text-[10px] flex items-center gap-2 shadow-sm">
            <Hash size={12} className="text-primary" /> {tag.Label}
          </div>
        ))}
      </div>
    </div>
  );
};
